# Fair dispatch: limit each consumer to a few unacked messages at a time.
ch.basic_qos(prefetch_count=10)   # at most 10 in-flight (unacked) per consumer

def on_message(ch, method, props, body):
    try:
        handle(body)
        ch.basic_ack(delivery_tag=method.delivery_tag)         # success -> remove
    except TransientError:
        # requeue=True puts it back for retry (beware infinite redelivery loops)
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
    except PoisonError:
        # requeue=False -> drop or route to a dead-letter exchange if configured
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

ch.basic_consume(queue='eu_orders', on_message_callback=on_message)  # auto_ack defaults False

ch.confirm_delivery()   # put channel into publisher-confirm mode

try:
    ch.basic_publish(
        exchange='orders', routing_key='order.eu.created',
        body=body,
        properties=pika.BasicProperties(delivery_mode=2, message_id='evt-42'),
        mandatory=True,     # ensures it is routable; unroutable -> returned, not silently dropped
    )
    # In pika BlockingConnection, basic_publish raises if the broker NACKs.
except pika.exceptions.UnroutableError:
    handle_unroutable(body)
except pika.exceptions.NackError:
    resend_later(body)      # broker could not accept responsibility

# BEFORE: infinite requeue loop on a poison message.
def on_message(ch, method, props, body):
    try:
        process(body)
        ch.basic_ack(method.delivery_tag)
    except Exception:
        ch.basic_nack(method.delivery_tag, requeue=True)   # <-- poison loop

# AFTER: bounded retries via a death-count header, then dead-letter.
MAX_RETRIES = 5

def on_message(ch, method, props, body):
    try:
        process(body)
        ch.basic_ack(method.delivery_tag)
    except Exception:
        deaths = count_deaths(props)   # read x-death header set by the DLX cycle
        if deaths >= MAX_RETRIES:
            ch.basic_nack(method.delivery_tag, requeue=False)  # -> DLX -> orders.dlq
        else:
            ch.basic_nack(method.delivery_tag, requeue=False)  # -> wait queue (TTL) -> back

