def make_handler(processed_ids):
    def on_message(ch, method, props, body):
        msg_id = props.message_id
        if not msg_id:
            # No id: cannot dedup safely. Send to DLX for inspection rather than guess.
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            return

        # Atomically claim the id. False => we already processed this message.
        if not processed_ids.add_if_absent(msg_id):
            ch.basic_ack(delivery_tag=method.delivery_tag)   # duplicate: ack and drop
            return

        try:
            process_order(body)                              # the real side effect
            ch.basic_ack(delivery_tag=method.delivery_tag)   # success
        except TransientError:
            # Roll back our claim so a legitimate retry can reprocess.
            processed_ids.remove(msg_id)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)  # -> retry via DLX
        except PermanentError:
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)  # -> dead-letter
    return on_message

